//! Integration tests for `operations::get`.
//!
//! Each test stages and tears down its own data via `iput` / `imkdir`,
//! then drives `get_one` (or `get_one_annotated`) against the live
//! server. Drop guards run regardless of assertion outcome so the
//! tests stay idempotent.

use std::process::Command;

use base64::engine::general_purpose;
use base64::Engine;

use baton_rs::operations::get::{get_one, get_one_annotated, GetOptions};
use baton_rs::types::{Collection, DataObject};
use baton_rs::{RodsConnection, Target};

/// Drop guard: `irm -r -f` removes data objects and populated
/// collections alike. Errors are swallowed because a test that fails
/// before staging may have nothing to clean up.
struct IrodsCleanup(String);
impl Drop for IrodsCleanup {
    fn drop(&mut self) {
        let _ = Command::new("irm").args(["-r", "-f", &self.0]).status();
    }
}

fn iput(local: &str, remote: &str) {
    let status = Command::new("iput")
        .args(["-f", local, remote])
        .status()
        .expect("failed to spawn iput");
    assert!(status.success(), "iput {} {} failed", local, remote);
}

#[test]
fn get_inline_round_trips_data_object_bytes() {
    // Use bytes that exercise both ASCII and high-bit content so any
    // base64 / encoding bug shows up.
    let local = "/tmp/baton_rs_get_inline";
    let content: Vec<u8> = (0u8..=255u8).collect();
    std::fs::write(local, &content).expect("write");

    let remote_coll = "/testZone/home/irods";
    let data_object = "baton_rs_get_inline";
    let remote = format!("{}/{}", remote_coll, data_object);
    iput(local, &remote);
    let _cleanup = IrodsCleanup(remote.clone());

    let mut conn = RodsConnection::connect_from_env().expect("connect_from_env");
    conn.login_from_auth_file().expect("login_from_auth_file");

    let input = Target::DataObject(DataObject {
        collection: remote_coll.to_string(),
        data_object: data_object.to_string(),
        size: None,
        checksum: None,
        data: None,
        avus: None,
        access: None,
        replicates: None,
        timestamps: None,
        error: None,
    });

    let output = get_one(&mut conn, input, &GetOptions::default()).expect("get_one");

    let d = match output {
        Target::DataObject(d) => d,
        other => panic!("expected DataObject on output, got {:?}", other),
    };
    let encoded = d.data.as_deref().expect("data field populated");
    let decoded = general_purpose::STANDARD
        .decode(encoded)
        .expect("base64 decode");

    assert_eq!(
        decoded, content,
        "byte-for-byte mismatch between iput input and get_one output"
    );
}

